; マップを開いた時に必ず実行されるスクリプト
[initial]

if(game.party.hasItem(o.水の腕輪)) tf.temp = %[type: "floor", img: "sea", trap: void, icon: 1, enemy: "none"];
else tf.temp = %[type: "water", img: "pool", trap: "water"];
for(var i = 3; i <= 6; i++) changeObject(tf.temp, 7, i, "f");

[endinitial]
