*event_2
;[exp] onObjectTrigger

@roadguide s="Water Palace"

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@roadguide n=Orchard w="Seagull Village" e="Water Dragon Temple"

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("power", 1)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had Strength permanently increased by 1!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("luck", 2)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had Luck permanently increased by 2!"'

[eventoff]
